'use client';
import { useParams } from 'next/navigation';
import EventDetails from '@/components/ui/eventDetials';
import { useAuth } from '@/context/AuthContext';
import { useEffect, useState } from 'react';
import { EventCategory } from '@/types/type';
import { fetchEvents } from '@/constants/fetchEvents';
import NotFound from '@/components/ui/NotFound';

const EventDetailsPage = () => {
  const params = useParams();
  const { token, userRole } = useAuth();
  const [event, setEvent] = useState<EventCategory | null>(null);

  const eventId = params.eventId as string;

  useEffect(() => {
    if (token) {
      fetchEvents(token, eventId).then((data) => {
        setEvent(data);
      });
    }
  }, [token, eventId]);

  return (
    <>
      {event ? (
        <EventDetails
          event={event}
          userRole={userRole}
        />
      ) : (
        <NotFound message='Event not found' />
      )}
    </>
  );
};

export default EventDetailsPage;
