import { EventCategory } from '@/types/type';

export const fetchEvents = async (
  token: string,
  eventId: string,
): Promise<EventCategory | null> => {
  try {
    const res = await fetch(`http://localhost:8080/events/${eventId}`, {
      method: 'GET',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
    });

    if (!res.ok) {
      throw new Error(`Failed to fetch event: ${res.statusText}`);
    }

    const data = await res.json();
    return data.event;
  } catch (error) {
    console.error('Error fetching event:', error);
    return null;
  }
};
