'use client';
import Image from 'next/image';
import {
  CalendarDays,
  Clock,
  Locate,
  Users,
  Ticket,
  Building,
  Layers,
  UserCircle,
  CheckCircle2,
  XCircle,
  Loader2,
  CalendarCheck2,
} from 'lucide-react';
import { EventCategory } from '@/types/type';
import { Button } from '@/components/ui/button';
import { UserRole } from '@/context/AuthContext';

const EventDetails = ({
  event,
  userRole,
}: {
  event: EventCategory;
  userRole: UserRole;
}) => {
  const baseURL = 'http://localhost:8080';
  const src = encodeURI(`${baseURL}/${event?.image?.replace(/\\/g, '/')}`);

  return (
    <div className='min-h-screen bg-white'>
      {/* القسم العلوي */}
      <section className='bg-gradient-to-r from-pink-500 to-purple-700 text-white py-10 px-6'>
        <div className='max-w-7xl mx-auto flex flex-col lg:flex-row items-center'>
          {/* صورة الحدث */}
          <div className='w-full lg:w-1/2'>
            <Image
              src={src}
              alt={event.title}
              width={600}
              height={400}
              className='rounded-lg shadow-lg'
              priority
            />
            {!event.price && (
              <span className='inline-block mt-4 bg-purple-800 text-white text-xs px-3 py-1 rounded-full shadow'>
                FREE
              </span>
            )}
          </div>

          {/* تفاصيل مختصرة */}
          <div className='w-full lg:w-1/2 mt-6 lg:mt-0 lg:pl-12'>
            <h1 className='text-3xl font-bold mb-4'>{event.title}</h1>
            <p className='mb-6 text-sm opacity-90'>{event.description}</p>

            <ul className='space-y-3 text-sm'>
              <li className='flex items-center'>
                <Locate className='w-4 h-4 mr-2' />
                <span>Location: {event.location}</span>
              </li>
              <li className='flex items-center'>
                <CalendarDays className='w-4 h-4 mr-2' />
                <span>Date: {new Date(event.date).toLocaleDateString()}</span>
              </li>
              <li className='flex items-center'>
                <Clock className='w-4 h-4 mr-2' />
                <span>Time: {event.time}</span>
              </li>
              <li className='flex items-center'>
                <Ticket className='w-4 h-4 mr-2' />
                <span>
                  Entry:{' '}
                  {event.price === 0 ? 'Absolutely FREE' : `${event.price} USD`}
                </span>
              </li>
              <li className='flex items-center'>
                <Users className='w-4 h-4 mr-2' />
                <span>Capacity: {event.capacity}</span>
              </li>
            </ul>

            {userRole === 'user' && (
              <div className='flex gap-4 mt-6'>
                <Button className='bg-purple-600 hover:bg-purple-700 text-white shadow'>
                  Register Event
                </Button>
                <Button
                  variant='outline'
                  className='border-white text-white hover:bg-white hover:text-purple-700'
                >
                  Learn More
                </Button>
              </div>
            )}
          </div>
        </div>
      </section>

      {/* تفاصيل إضافية */}
      <section className='px-6 py-12 max-w-4xl mx-auto space-y-6'>
        <h2 className='text-2xl font-bold text-purple-700 mb-4'>
          More Details
        </h2>

        <div className='grid grid-cols-1 sm:grid-cols-2 gap-6 text-sm'>
          <div className='flex items-center'>
            <Building className='w-4 h-4 mr-2 text-purple-600' />
            <span>Hall: {event.hall?.name || 'Not specified'}</span>
          </div>
          <div className='flex items-center'>
            <Layers className='w-4 h-4 mr-2 text-purple-600' />
            <span>Category: {event.category?.name || 'Uncategorized'}</span>
          </div>
          <div className='flex items-center'>
            <UserCircle className='w-4 h-4 mr-2 text-purple-600' />
            <span>Host: {event.host}</span>
          </div>
          <div className='flex items-center'>
            {event.status === 'approved' && (
              <CheckCircle2 className='w-4 h-4 mr-2 text-green-600' />
            )}
            {event.status === 'pending' && (
              <Loader2 className='w-4 h-4 mr-2 text-yellow-500 animate-spin' />
            )}
            {event.status === 'rejected' && (
              <XCircle className='w-4 h-4 mr-2 text-red-600' />
            )}
            <span>Status: {event.status}</span>
          </div>
          <div className='flex items-center'>
            <CalendarCheck2 className='w-4 h-4 mr-2 text-purple-600' />
            <span>
              Starts: {new Date(event.startDate).toLocaleDateString()}
            </span>
          </div>
          <div className='flex items-center'>
            <CalendarCheck2 className='w-4 h-4 mr-2 text-purple-600' />
            <span>Ends: {new Date(event.endDate).toLocaleDateString()}</span>
          </div>
        </div>

        <div className='text-xs text-gray-500 mt-6'>
          Created at: {new Date(event.createdAt).toLocaleString()} <br />
          Updated at: {new Date(event.updatedAt).toLocaleString()}
        </div>
      </section>
    </div>
  );
};

export default EventDetails;
